import { FormEvent, useState, useRef } from 'react';
import { LockClosedIcon } from '@heroicons/react/24/solid';
import {
  Form,
  useLoaderData,
  useNavigate,
  useOutletContext,
} from '@remix-run/react';
import { OutletContext } from '~/types';
import { DataFunctionArgs, json, redirect } from '@remix-run/server-runtime';
import {
  getAvailableCountries,
  getEligibleShippingMethods,
} from '~/providers/checkout/checkout';
import { shippingFormDataIsValid } from '~/utils/validation';
import { getSessionStorage } from '~/sessions';
import { classNames } from '~/utils/class-names';
import { getActiveCustomerAddresses } from '~/providers/customer/customer';
import { AddressForm } from '~/components/account/AddressForm';
import { ShippingMethodSelector } from '~/components/checkout/ShippingMethodSelector';
import { ShippingAddressSelector } from '~/components/checkout/ShippingAddressSelector';
import { getActiveOrder } from '~/providers/orders/order';
import { useTranslation } from 'react-i18next';

export async function loader({ request }: DataFunctionArgs) {
  try {
    const sessionStorage = await getSessionStorage();
    const session = await sessionStorage.getSession(request.headers.get('Cookie'));
    console.log('CHECKOUT LOADER: session retrieved');

    const authToken = session.get('authToken');
    console.log('CHECKOUT LOADER: authToken exists:', !!authToken);

    const orderResult = await getActiveOrder({ request, authToken });
    const activeOrder = orderResult.activeOrder;
    console.log('CHECKOUT LOADER: activeOrder:', activeOrder ? `code=${activeOrder.code}, active=${activeOrder.active}, lines=${activeOrder.lines?.length || 0}` : 'null');

    if (
      !session ||
      !activeOrder ||
      !activeOrder.active ||
      activeOrder.lines.length === 0
    ) {
      console.log('CHECKOUT LOADER: redirecting to /');
      return redirect('/');
    }
    
    const { availableCountries } = await getAvailableCountries({ request });
    console.log('CHECKOUT LOADER: availableCountries:', availableCountries?.length || 0);
    
    const { eligibleShippingMethods } = await getEligibleShippingMethods({
      request,
    });
    console.log('CHECKOUT LOADER: eligibleShippingMethods:', eligibleShippingMethods?.length || 0);
    
    const { activeCustomer } = await getActiveCustomerAddresses({ request });
    console.log('CHECKOUT LOADER: activeCustomer:', activeCustomer?.id ? `id=${activeCustomer.id}` : 'null');
    
    const error = session.get('activeOrderError');
    console.log('CHECKOUT LOADER: returning json data');
    
    return json({
      availableCountries,
      eligibleShippingMethods,
      activeCustomer,
      error,
    });
  } catch (e) {
    console.error('CHECKOUT LOADER ERROR:', e);
    throw e;
  }
}

export default function CheckoutShipping() {
  const { availableCountries, eligibleShippingMethods, activeCustomer, error } =
    useLoaderData<typeof loader>();
  const { activeOrderFetcher, activeOrder } = useOutletContext<OutletContext>();
  const [customerFormChanged, setCustomerFormChanged] = useState(false);
  const [addressFormChanged, setAddressFormChanged] = useState(false);
  const [selectedAddressIndex, setSelectedAddressIndex] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const customerFormRef = useRef<HTMLFormElement>(null);
  const addressFormRef = useRef<HTMLFormElement>(null);
  const navigate = useNavigate();
  const { t } = useTranslation();

  const { customer, shippingAddress } = activeOrder ?? {};
  const isSignedIn = !!activeCustomer?.id;
  const addresses = activeCustomer?.addresses ?? [];
  const defaultFullName =
    shippingAddress?.fullName ??
    (customer ? `${customer.firstName} ${customer.lastName}` : ``);
  
  const hasCustomerInfo = customer?.emailAddress && customer?.firstName && customer?.lastName;
  const hasShippingAddress = shippingAddress?.streetLine1 && shippingAddress?.postalCode;
  const hasSelectedAddress = isSignedIn && addresses.length > 0 && selectedAddressIndex >= 0;
  const hasShippingMethod = activeOrder?.shippingLines?.length > 0;

  const canProceedToPayment =
    hasCustomerInfo &&
    (hasShippingAddress || hasSelectedAddress) &&
    hasShippingMethod &&
    activeOrder?.lines?.length > 0;

  const submitCustomerFormData = () => {
    if (!customerFormRef.current) return;
    
    const formData = new FormData(customerFormRef.current);
    const { emailAddress, firstName, lastName } = Object.fromEntries<any>(
      formData.entries(),
    );
    
    if (customerFormRef.current.checkValidity() && emailAddress && firstName && lastName) {
      activeOrderFetcher.submit(formData, {
        method: 'post',
        action: '/api/active-order',
      });
      setCustomerFormChanged(false);
    }
  };

  const submitAddressFormData = () => {
    if (!addressFormRef.current) return;
    
    const formData = new FormData(addressFormRef.current);
    
    if (addressFormRef.current.checkValidity() && shippingFormDataIsValid(formData)) {
      activeOrderFetcher.submit(formData, {
        method: 'post',
        action: '/api/active-order',
      });
      setAddressFormChanged(false);
    }
  };

  const handleCustomerFormSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    submitCustomerFormData();
  };

  const handleCustomerBlur = () => {
    // Auto-submit when all required fields are filled
    if (customerFormRef.current) {
      const formData = new FormData(customerFormRef.current);
      const emailAddress = formData.get('emailAddress');
      const firstName = formData.get('firstName');
      const lastName = formData.get('lastName');
      if (emailAddress && firstName && lastName && customerFormRef.current.checkValidity()) {
        submitCustomerFormData();
      }
    }
  };

  const handleAddressFormSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    submitAddressFormData();
  };

  const handleAddressBlur = () => {
    // Auto-submit when all required address fields are filled
    if (addressFormRef.current && shippingFormDataIsValid(new FormData(addressFormRef.current))) {
      submitAddressFormData();
    }
  };

  const submitSelectedAddress = (index: number) => {
    const selectedAddress = activeCustomer?.addresses?.[index];
    if (selectedAddress) {
      setSelectedAddressIndex(index);
      const formData = new FormData();
      Object.keys(selectedAddress).forEach((key) =>
        formData.append(key, (selectedAddress as any)[key]),
      );
      formData.append('countryCode', selectedAddress.country.code);
      formData.append('action', 'setCheckoutShipping');
      activeOrderFetcher.submit(formData, {
        method: 'post',
        action: '/api/active-order',
      });
    }
  };

  const submitSelectedShippingMethod = (value?: string) => {
    if (value) {
      activeOrderFetcher.submit(
        {
          action: 'setShippingMethod',
          shippingMethodId: value,
        },
        {
          method: 'post',
          action: '/api/active-order',
        },
      );
    }
  };

  const navigateToPayment = async () => {
    if (isSubmitting || !canProceedToPayment) return;
    
    setIsSubmitting(true);
    
    if (!isSignedIn && customerFormChanged && customerFormRef.current) {
      await submitCustomerFormData();
    }
    
    if (!hasShippingAddress && !hasSelectedAddress && addressFormRef.current && addressFormChanged) {
      await submitAddressFormData();
    }
    
    setTimeout(() => {
      setIsSubmitting(false);
      navigate('./payment');
    }, 300);
  };

  return (
    <div>
      <div>
        <h2 className="text-lg font-medium text-gray-900">
          {t('checkout.detailsTitle')}
        </h2>

        {isSignedIn ? (
          <div>
            <p className="mt-2 text-gray-600">
              {customer?.firstName} {customer?.lastName}
            </p>
            <p>{customer?.emailAddress}</p>
          </div>
        ) : (
          <Form
            ref={customerFormRef}
            method="post"
            action="/api/active-order"
            onSubmit={handleCustomerFormSubmit}
            onChange={() => setCustomerFormChanged(true)}
          >
            <input type="hidden" name="action" value="setOrderCustomer" />
            <div className="mt-4">
              <label
                htmlFor="emailAddress"
                className="block text-sm font-medium text-gray-700"
              >
                {t('account.emailAddress')}
              </label>
              <div className="mt-1">
                <input
                  type="email"
                  id="emailAddress"
                  name="emailAddress"
                  autoComplete="email"
                  defaultValue={customer?.emailAddress}
                  required
                  onBlur={handleCustomerBlur}
                  className="block w-full border-gray-300 rounded-md shadow-sm focus:ring-primary-500 focus:border-primary-500 sm:text-sm"
                />
              </div>
              {error?.errorCode === 'EMAIL_ADDRESS_CONFLICT_ERROR' && (
                <p className="mt-2 text-sm text-red-600" id="email-error">
                  {error.message}
                </p>
              )}
            </div>
            <div className="mt-4 grid grid-cols-1 gap-y-6 sm:grid-cols-2 sm:gap-x-4">
              <div>
                <label
                  htmlFor="firstName"
                  className="block text-sm font-medium text-gray-700"
                >
                  {t('account.firstName')}
                </label>
                <div className="mt-1">
                  <input
                    type="text"
                    id="firstName"
                    name="firstName"
                    autoComplete="given-name"
                    defaultValue={customer?.firstName}
                    required
                    onBlur={handleCustomerBlur}
                    className="block w-full border-gray-300 rounded-md shadow-sm focus:ring-primary-500 focus:border-primary-500 sm:text-sm"
                  />
                </div>
              </div>

              <div>
                <label
                  htmlFor="lastName"
                  className="block text-sm font-medium text-gray-700"
                >
                  {t('account.lastName')}
                </label>
                <div className="mt-1">
                  <input
                    type="text"
                    id="lastName"
                    name="lastName"
                    autoComplete="family-name"
                    defaultValue={customer?.lastName}
                    required
                    onBlur={handleCustomerBlur}
                    className="block w-full border-gray-300 rounded-md shadow-sm focus:ring-primary-500 focus:border-primary-500 sm:text-sm"
                  />
                </div>
              </div>
            </div>
          </Form>
        )}
      </div>

      <Form
        ref={addressFormRef}
        method="post"
        action="/api/active-order"
        onSubmit={handleAddressFormSubmit}
        onChange={() => setAddressFormChanged(true)}
      >
        <input type="hidden" name="action" value="setCheckoutShipping" />
        <div className="mt-10 border-t border-gray-200 pt-10">
          <h2 className="text-lg font-medium text-gray-900">
            {t('checkout.shippingTitle')}
          </h2>
        </div>
        {isSignedIn && activeCustomer.addresses?.length ? (
          <div>
            <ShippingAddressSelector
              addresses={activeCustomer.addresses}
              selectedAddressIndex={selectedAddressIndex}
              onChange={submitSelectedAddress}
            />
            <div className="mt-4">
              <button
                type="button"
                onClick={() => setSelectedAddressIndex(-1)}
                className="text-sm text-primary-600 hover:text-primary-800"
              >
                {t('checkout.addNewAddress')}
              </button>
            </div>
          </div>
        ) : (
          <AddressForm
            availableCountries={availableCountries}
            address={shippingAddress}
            defaultFullName={defaultFullName}
            onBlur={handleAddressBlur}
          ></AddressForm>
        )}
        {isSignedIn && !activeCustomer.addresses?.length && (
          <AddressForm
            availableCountries={availableCountries}
            address={shippingAddress}
            defaultFullName={defaultFullName}
            onBlur={handleAddressBlur}
          ></AddressForm>
        )}
      </Form>

      <div className="mt-10 border-t border-gray-200 pt-10">
        <ShippingMethodSelector
          eligibleShippingMethods={eligibleShippingMethods}
          currencyCode={activeOrder?.currencyCode}
          shippingMethodId={
            activeOrder?.shippingLines[0]?.shippingMethod.id ?? ''
          }
          onChange={submitSelectedShippingMethod}
        />
      </div>

      <button
        type="button"
        disabled={!canProceedToPayment || isSubmitting}
        onClick={navigateToPayment}
        className={classNames(
          canProceedToPayment && !isSubmitting
            ? 'bg-primary-600 hover:bg-primary-700'
            : 'bg-gray-400',
          'flex w-full items-center justify-center space-x-2 mt-24 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500',
        )}
      >
        <LockClosedIcon className="w-5 h-5"></LockClosedIcon>
        <span>{isSubmitting ? t('checkout.processing') : t('checkout.goToPayment')}</span>
      </button>
    </div>
  );
}
